const input = $input.first().json;

const VALID_PURPOSES = ['report', 'tl_internal', 'dev_self'];
const purpose = String(input.purpose || '');
if (!VALID_PURPOSES.includes(purpose)) {
  throw new Error('F-14: purpose must be one of: ' + VALID_PURPOSES.join(', '));
}

const callerId = String(input.caller_discord_id || '');

// Validate caller_discord_id format (snowflake: 17-19 digits) when provided
if (callerId && !/^\d{17,19}$/.test(callerId)) {
  throw new Error('F-14: caller_discord_id must be a Discord snowflake (17-19 digits)');
}

// dev_self requires a caller
if (purpose === 'dev_self' && !callerId) {
  throw new Error('F-14: caller_discord_id is required for purpose=dev_self');
}

return [{ json: { purpose, safe_caller_id: callerId } }];

const validated = $('Validate Input').item.json;
const purpose = validated.purpose;

// Project signals — always safe, already aggregated (project-level)
const signalRows = $('Fetch Project Signals').all().filter(r => r.json.feature_area != null);
const featureAreas = signalRows.map(r => ({
  area: r.json.feature_area,
  status: r.json.status_summary,
  has_blocker: r.json.has_blocker,
  source: r.json.source,
  last_signal: r.json.last_primary_signal_at
}));

// bootstrapping: no standup-sourced project signals have been built yet (F-14.6)
// Supplementary signals may exist while bootstrapping is still true.
const bootstrapping = !featureAreas.some(a => a.source === 'standup');

// Last standup date — derived from standup-sourced project signals
const standupSignals = featureAreas
  .filter(a => a.source === 'standup' && a.last_signal)
  .map(a => a.last_signal)
  .sort();
const lastStandupDate = standupSignals.length > 0 ? standupSignals[standupSignals.length - 1] : null;

// Recent Q&A — always safe (project-level)
const qaRows = $('Fetch QA History').all().filter(r => r.json.question_text != null);
const recentQA = qaRows.map(r => ({
  question: r.json.question_text,
  answer: r.json.answer_text,
  area: r.json.feature_area,
  when: r.json.asked_at
}));

// F-08.3: on a small team, a per-area blocker flag re-identifies who is blocked
// (e.g. a single known owner per area) just as surely as a name would. This applies
// to dev_self too: its project_picture covers every teammate's area, not only the
// caller's own, so it is not a purely-self view.
const activeDevRows = $('Fetch Active Developer Count').all();
const totalActiveDevelopers = Number(activeDevRows[0]?.json?.active_developer_count ?? 0);
const smallTeam = totalActiveDevelopers < 3;

// F-08.1: the Client boundary (Tier 1) is stricter than tl_internal (Tier 2) — Tier 1
// forbids individual attribution "of any kind, named or anonymised", while Tier 2
// explicitly permits anonymised work-area signals (F-08.2's own example: "one developer
// on the auth feature... blocked"). A single-owner feature area re-identifies its owner
// regardless of total team size, and team size alone can't detect that case without a
// per-area contributor count this workflow doesn't compute — so for 'report', never
// surface has_blocker at all rather than rely on a team-size threshold that can miss it.
const stripBlockerFlag = purpose === 'report' || smallTeam;
const visibleFeatureAreas = stripBlockerFlag
  ? featureAreas.map(({ has_blocker, ...rest }) => rest)
  : featureAreas;

const result = {
  purpose,
  bootstrapping,
  project_picture: {
    feature_areas: visibleFeatureAreas,
    last_standup_date: lastStandupDate,
    recent_qa: recentQA
  }
};

// dev_self: caller must be in active roster; include their own standup records only
// SC-14: raw individual data returned only to the person themselves (HIGH-2)
if (purpose === 'dev_self') {
  const rosterRows = $('Verify Caller In Roster').all().filter(r => r.json.discord_id != null);
  if (rosterRows.length === 0) {
    throw new Error('F-14: caller_discord_id is not an active roster member');
  }
  const standupRows = $('Fetch Own Standup Records').all().filter(r => r.json.standup_date != null);
  result.own_standups = standupRows.map(r => ({
    date: r.json.standup_date,
    text: r.json.raw_text,
    area: r.json.feature_area,
    has_blocker: r.json.has_blocker
  }));
}

// tl_internal: anonymised blocker signals (counts only, no names)
// SC-03 Tier 2: work-area signals without naming any individual
if (purpose === 'tl_internal') {
  const blockerRows = $('Fetch Blocker Count').all();
  const bc = blockerRows[0]?.json ?? {};
  const rawDeveloperCount = Number(bc.developer_count ?? 0);

  // F-08.3: on a small team, an exact count re-identifies who is blocked
  // (e.g. "1 of 2 developers blocked" names that person as surely as their handle).
  // Below the threshold, collapse to a category instead of a number.
  const developerBlockerSignal = smallTeam
    ? (rawDeveloperCount > 0 ? 'some' : 'none')
    : rawDeveloperCount;

  // F-08.3: an exact area count is just as re-identifying as the developer count on a
  // small team (e.g. "blockers in 2 of 3 areas" narrows it down as much as a name would
  // once the TL knows who owns which area). Collapse it the same way.
  const rawAreaCount = Number(bc.area_count ?? 0);
  const areaBlockerSignal = smallTeam
    ? (rawAreaCount > 0 ? 'some' : 'none')
    : rawAreaCount;

  result.internal_signals = {
    active_blocker_developer_count: developerBlockerSignal,
    active_blocker_area_count: areaBlockerSignal
  };
}

return [{ json: result }];
